4373 static Value *simplifyWithOpReplaced(Value *V, Value *Op, Value *RepOp,
4374                                      const SimplifyQuery &Q,
4375                                      bool AllowRefinement,
4376                                      SmallVectorImpl<Instruction *> *DropFlags,
4377                                      unsigned MaxRecurse) {
4378   // Trivial replacement.
4379   if (V == Op)
4380     return RepOp;
4381 
4382   if (!MaxRecurse--)
4383     return nullptr;
4384 
4385   // We cannot replace a constant, and shouldn't even try.
4386   if (isa<Constant>(Op))
4387     return nullptr;
