2850 void ConstantDataSequential::destroyConstantImpl() {
2851   // Remove the constant from the StringMap.
2852   StringMap<std::unique_ptr<ConstantDataSequential>> &CDSConstants =
2853       getType()->getContext().pImpl->CDSConstants;
2854 
2855   auto Slot = CDSConstants.find(getRawDataValues());
2856 
2857   assert(Slot != CDSConstants.end() && "CDS not found in uniquing table");
2858 
2859   std::unique_ptr<ConstantDataSequential> *Entry = &Slot->getValue();
2860 
2861   // Remove the entry from the hash table.
2862   if (!(*Entry)->Next) {
2863     // If there is only one value in the bucket (common case) it must be this
2864     // entry, and removing the entry should remove the bucket completely.
2865     assert(Entry->get() == this && "Hash mismatch in ConstantDataSequential");
2866     getContext().pImpl->CDSConstants.erase(Slot);
2867     return;
2868   }
2869 
2870   // Otherwise, there are multiple entries linked off the bucket, unlink the
2871   // node we care about but keep the bucket around.
2872   while (true) {
2873     std::unique_ptr<ConstantDataSequential> &Node = *Entry;
2874     assert(Node && "Didn't find entry in its uniquing hash table!");
2875     // If we found our entry, unlink it from the list and we're done.
2876     if (Node.get() == this) {
2877       Node = std::move(Node->Next);
2878       return;
2879     }
2880 
2881     Entry = &Node->Next;
2882   }
2883 }
