1654   // For and-of-compares, check if the intersection is empty:
1655   // (icmp X, C0) && (icmp X, C1) --> empty set --> false
1656   if (IsAnd && Range0.intersectWith(Range1).isEmptySet())
1657     return getFalse(Cmp0->getType());
