1862 
1863   if (Value *X = simplifyAndOfICmpsWithAdd(Op0, Op1, Q.IIQ))
1864     return X;
1865   if (Value *X = simplifyAndOfICmpsWithAdd(Op1, Op0, Q.IIQ))
1866     return X;
1867 
1868   return nullptr;
1869 }
